import 'dart:async';
import 'dart:io';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

// These imports reference the code generated by flutter_rust_bridge_codegen
import 'src/rust/api/mod.dart' as api;
import 'src/rust/frb_generated.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  
  try {
    await RustLib.init();
  } catch (e) {
    debugPrint("RustLib initialization skipped or failed (likely running without compiled binaries): $e");
  }

  runApp(const ClipboardSyncApp());
}

class ClipboardSyncApp extends StatelessWidget {
  const ClipboardSyncApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'SyncBoard P2P',
      debugShowCheckedModeBanner: false,
      theme: ThemeData.dark().copyWith(
        scaffoldBackgroundColor: const Color(0xFF0B132B), // Deep Space Blue
        colorScheme: ColorScheme.fromSeed(
          seedColor: const Color(0xFF00B4D8), // Neon Blue
          brightness: Brightness.dark,
          primary: const Color(0xFF00B4D8),
          secondary: const Color(0xFF70E000), // Lime Green
        ),
        cardColor: const Color(0xFF1C2541), // Space Cadet Blue
      ),
      home: const SyncHomeScreen(),
    );
  }
}

class SyncHomeScreen extends StatefulWidget {
  const SyncHomeScreen({super.key});

  @override
  State<SyncHomeScreen> createState() => _SyncHomeScreenState();
}

class _SyncHomeScreenState extends State<SyncHomeScreen> {
  static const _serviceChannel = MethodChannel('com.example.clipboard/service');
  
  bool _isSyncEnabled = false;
  String _localIp = "Detecting...";
  String _device_id = "Loading...";
  final _nameController = TextEditingController();
  final List<String> _logs = [];
  List<dynamic> _peers = []; // Dynamic to handle generated Peer class
  
  StreamSubscription? _rustEventSub;
  Timer? _androidClipboardTimer;
  Timer? _peerRefreshTimer;
  String _lastClipboardText = "";

  @override
  void initState() {
    super.initState();
    _nameController.text = Platform.isAndroid ? "Android Device" : "Linux Laptop";
    _initRustEngine();
    _detectLocalIp();
    _loadDeviceId();
  }

  @override
  void dispose() {
    _rustEventSub?.cancel();
    _androidClipboardTimer?.cancel();
    _peerRefreshTimer?.cancel();
    _nameController.dispose();
    super.dispose();
  }

  Future<void> _loadDeviceId() async {
    try {
      final id = await api.getDeviceId();
      setState(() {
        _device_id = id;
      });
    } catch (_) {
      setState(() {
        _device_id = "local-dev-id";
      });
    }
  }

  Future<void> _detectLocalIp() async {
    try {
      for (var interface in await NetworkInterface.list()) {
        for (var addr in interface.addresses) {
          if (addr.type == InternetAddressType.IPv4 && !addr.isLoopback) {
            setState(() {
              _localIp = addr.address;
            });
            return;
          }
        }
      }
      setState(() {
        _localIp = "No active LAN connection";
      });
    } catch (e) {
      setState(() {
        _localIp = "Error: $e";
      });
    }
  }

  void _initRustEngine() {
    try {
      _rustEventSub = api.initApp().listen((event) {
        _handleRustEvent(event);
      }, onError: (e) {
        _log("Rust stream error: $e");
      });
    } catch (e) {
      _log("Could not listen to Rust events: $e");
    }
  }

  void _handleRustEvent(dynamic event) {
    final eventStr = event.toString();
    
    if (eventStr.contains("ClipboardUpdated")) {
      String? content;
      try {
        content = (event as dynamic).content;
      } catch (_) {
        final match = RegExp(r"content: (.*)}").firstMatch(eventStr);
        content = match?.group(1);
      }
      
      if (content != null && content != _lastClipboardText) {
        _lastClipboardText = content;
        Clipboard.setData(ClipboardData(text: content));
        _log("Sync in: '${content.length > 25 ? '${content.substring(0, 25)}...' : content}'");
      }
    } else if (eventStr.contains("ConnectionStatus")) {
      String message = "";
      try {
        message = (event as dynamic).message;
      } catch (_) {
        final match = RegExp(r"message: (.*)}").firstMatch(eventStr);
        message = match?.group(1) ?? "";
      }
      _log(message);
    } else if (eventStr.contains("Error")) {
      String message = "";
      try {
        message = (event as dynamic).message;
      } catch (_) {
        final match = RegExp(r"message: (.*)}").firstMatch(eventStr);
        message = match?.group(1) ?? "";
      }
      _log("Core error: $message");
    }
  }

  void _log(String message) {
    final timestamp = DateTime.now().toIso8601String().substring(11, 19);
    setState(() {
      _logs.insert(0, "[$timestamp] $message");
      if (_logs.length > 40) _logs.removeLast();
    });
  }

  Future<void> _toggleSync(bool value) async {
    setState(() {
      _isSyncEnabled = value;
    });

    if (value) {
      _log("Initializing P2P network mesh...");
      final devName = _nameController.text.trim();
      
      if (Platform.isAndroid) {
        try {
          await _serviceChannel.invokeMethod('startForegroundService');
          _log("Foreground notification started");
        } catch (e) {
          _log("Foreground service error: $e");
        }
      }

      try {
        await api.startSync(
          deviceName: devName.isEmpty ? "P2P Device" : devName,
          isAndroid: Platform.isAndroid,
        );
        _log("Listening on UDP 45454. WS server active.");
        
        if (Platform.isAndroid) {
          _startAndroidClipboardPoller();
        }

        _startPeerRegistryRefresher();
      } catch (e) {
        _log("Failed to start P2P sync: $e");
      }
    } else {
      _log("Stopping P2P Sync...");
      _androidClipboardTimer?.cancel();
      _peerRefreshTimer?.cancel();
      
      if (Platform.isAndroid) {
        try {
          await _serviceChannel.invokeMethod('stopForegroundService');
        } catch (e) {
          _log("Failed to stop foreground service: $e");
        }
      }

      setState(() {
        _peers = [];
      });
    }
  }

  void _startPeerRegistryRefresher() {
    _peerRefreshTimer?.cancel();
    _peerRefreshTimer = Timer.periodic(const Duration(seconds: 2), (timer) async {
      if (!_isSyncEnabled) return;
      try {
        final peersList = await api.getDiscoveredPeers();
        setState(() {
          _peers = peersList;
        });
      } catch (_) {
        // Skips updating if library is not loaded
      }
    });
  }

  void _startAndroidClipboardPoller() {
    _androidClipboardTimer?.cancel();
    _androidClipboardTimer = Timer.periodic(const Duration(milliseconds: 500), (timer) async {
      if (!_isSyncEnabled) return;
      
      final clipData = await Clipboard.getData(Clipboard.kTextPlain);
      final text = clipData?.text;
      
      if (text != null && text.isNotEmpty && text != _lastClipboardText) {
        _lastClipboardText = text;
        _log("Clipboard copy: '${text.length > 25 ? '${text.substring(0, 25)}...' : text}'");
        try {
          await api.sendLocalClipboardUpdate(content: text);
        } catch (e) {
          _log("Send failed: $e");
        }
      }
    });
  }

  int get _connectedPeersCount {
    return _peers.where((p) => p.connectionStatus == "Connected").length;
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Scaffold(
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.all(20.0),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              // Title & Connection Count
              Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          'SyncBoard P2P',
                          style: theme.textTheme.headlineMedium?.copyWith(
                            fontWeight: FontWeight.w900,
                            color: Colors.white,
                            letterSpacing: -1.0,
                          ),
                        ),
                        const SizedBox(height: 4),
                        Text(
                          'ID: ${_device_id.length > 12 ? _device_id.substring(0, 12) : _device_id}...',
                          style: theme.textTheme.bodySmall?.copyWith(
                            color: Colors.slate[400],
                            fontFamily: 'monospace',
                          ),
                        ),
                      ],
                    ),
                  ),
                  Container(
                    padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 8),
                    decoration: BoxDecoration(
                      color: _isSyncEnabled ? const Color(0x1500B4D8) : const Color(0x10Slate),
                      borderRadius: BorderRadius.circular(12),
                      border: Border.all(
                        color: _isSyncEnabled ? const Color(0xFF00B4D8) : Colors.slate[700]!,
                        width: 1,
                      ),
                    ),
                    child: Row(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        if (_isSyncEnabled) ...[
                          const SizedBox(
                            width: 10,
                            height: 10,
                            child: CircularProgressIndicator(
                              strokeWidth: 2,
                              color: Color(0xFF00B4D8),
                            ),
                          ),
                          const SizedBox(width: 8),
                        ],
                        Text(
                          _isSyncEnabled ? 'P2P Active' : 'Offline',
                          style: TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.bold,
                            color: _isSyncEnabled ? const Color(0xFF00B4D8) : Colors.slate[400],
                          ),
                        ),
                      ],
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 20),

              // Device Config Card
              Card(
                elevation: 0,
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(16),
                  side: BorderSide(color: Colors.slate[800]!),
                ),
                child: Padding(
                  padding: const EdgeInsets.all(16.0),
                  child: Column(
                    children: [
                      Row(
                        children: [
                          Expanded(
                            child: TextField(
                              controller: _nameController,
                              enabled: !_isSyncEnabled,
                              decoration: InputDecoration(
                                labelText: 'Device Name',
                                hintText: 'e.g. My Phone',
                                border: OutlineInputBorder(
                                  borderRadius: BorderRadius.circular(8),
                                ),
                                contentPadding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
                              ),
                            ),
                          ),
                          const SizedBox(width: 12),
                          Column(
                            children: [
                              const Text('Sync', style: TextStyle(fontSize: 12, fontWeight: FontWeight.bold)),
                              Switch.adaptive(
                                value: _isSyncEnabled,
                                activeColor: theme.colorScheme.primary,
                                onChanged: _toggleSync,
                              ),
                            ],
                          ),
                        ],
                      ),
                      const SizedBox(height: 12),
                      Row(
                        mainAxisAlignment: MainAxisAlignment.spaceBetween,
                        children: [
                          Text(
                            'Local IP: $_localIp',
                            style: TextStyle(color: Colors.slate[400], fontSize: 12),
                          ),
                          Text(
                            'Connected Peers: $_connectedPeersCount',
                            style: TextStyle(
                              color: _connectedPeersCount > 0 ? const Color(0xFF70E000) : Colors.slate[400],
                              fontWeight: FontWeight.bold,
                              fontSize: 12,
                            ),
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
              const SizedBox(height: 16),

              // Discovered Peers Section
              Text(
                'Discovered Peers (${_peers.length})',
                style: theme.textTheme.titleSmall?.copyWith(
                  fontWeight: FontWeight.bold,
                  color: Colors.slate[300],
                ),
              ),
              const SizedBox(height: 8),

              Expanded(
                child: Container(
                  height: 160,
                  decoration: BoxDecoration(
                    color: const Color(0xFF0F172A),
                    borderRadius: BorderRadius.circular(12),
                    border: Border.all(color: Colors.slate[800]!),
                  ),
                  child: _peers.isEmpty
                      ? const Center(
                          child: Text(
                            'Searching for local devices...',
                            style: TextStyle(color: Colors.slate),
                          ),
                        )
                      : ListView.separated(
                          padding: const EdgeInsets.all(8),
                          itemCount: _peers.length,
                          separatorBuilder: (context, index) => const Divider(height: 8, color: Color(0x1FWhite)),
                          itemBuilder: (context, index) {
                            final peer = _peers[index];
                            final status = peer.connectionStatus;
                            Color statusColor = Colors.grey;
                            Widget? trailingIcon;
                            
                            if (status == "Connected") {
                              statusColor = const Color(0xFF70E000);
                              trailingIcon = const Icon(Icons.check_circle, color: Color(0xFF70E000), size: 20);
                            } else if (status == "Connecting") {
                              statusColor = const Color(0xFFFFB703);
                              trailingIcon = const SizedBox(
                                width: 16,
                                height: 16,
                                child: CircularProgressIndicator(strokeWidth: 2, color: Color(0xFFFFB703)),
                              );
                            } else {
                              trailingIcon = Icon(Icons.wifi_off, color: Colors.slate[600], size: 20);
                            }

                            final timeDiff = DateTime.now().millisecondsSinceEpoch ~/ 1000 - peer.lastSeen as int;
                            final seenStr = timeDiff < 5 ? "active" : "${timeDiff}s ago";

                            return ListTile(
                              dense: true,
                              title: Text(
                                peer.deviceName.isEmpty ? "Unknown" : peer.deviceName,
                                style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 14),
                              ),
                              subtitle: Text(
                                '${peer.ipAddress}:${peer.wsPort} • seen $seenStr',
                                style: TextStyle(color: Colors.slate[400], fontSize: 11),
                              ),
                              trailing: Row(
                                mainAxisSize: MainAxisSize.min,
                                children: [
                                  Text(
                                    status,
                                    style: TextStyle(color: statusColor, fontWeight: FontWeight.bold, fontSize: 12),
                                  ),
                                  const SizedBox(width: 8),
                                  if (trailingIcon != null) trailingIcon,
                                ],
                              ),
                            );
                          },
                        ),
                ),
              ),
              const SizedBox(height: 16),

              // Activity Logs Section
              Text(
                'Logs',
                style: theme.textTheme.titleSmall?.copyWith(
                  fontWeight: FontWeight.bold,
                  color: Colors.slate[300],
                ),
              ),
              const SizedBox(height: 8),

              Expanded(
                child: Container(
                  decoration: BoxDecoration(
                    color: const Color(0xFF030712), // Black Slate
                    borderRadius: BorderRadius.circular(12),
                    border: Border.all(color: Colors.slate[900]!),
                  ),
                  child: _logs.isEmpty
                      ? const Center(
                          child: Text(
                            'Logs are empty.',
                            style: TextStyle(color: Colors.slate),
                          ),
                        )
                      : ListView.builder(
                          padding: const EdgeInsets.all(10),
                          itemCount: _logs.length,
                          itemBuilder: (context, index) {
                            return Padding(
                              padding: const EdgeInsets.symmetric(vertical: 2.0),
                              child: Text(
                                _logs[index],
                                style: const TextStyle(
                                  fontFamily: 'monospace',
                                  fontSize: 11,
                                  color: Color(0xFF00B4D8), // Light Blue
                                ),
                              ),
                            );
                          },
                        ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}
